using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext(string? dbName = null)
        {
            var context = CreateContext(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructors = new List<Instructor>
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>(), OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" } },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() }
            };
            context.Instructors.AddRange(instructors);

            var departments = new List<Department>
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1, RowVersion = new byte[] { 0, 0, 0, 1 } },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2, RowVersion = new byte[] { 0, 0, 0, 2 } },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 200000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3, RowVersion = new byte[] { 0, 0, 0, 3 } }
            };
            context.Departments.AddRange(departments);

            var courses = new List<Course>
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() }
            };
            context.Courses.AddRange(courses);

            var students = new List<Student>
            {
                new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2005-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2002-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2003-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2002-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 5, FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2002-09-01"), Enrollments = new List<Enrollment>() }
            };
            context.Students.AddRange(students);

            var enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 2, CourseID = 4041, Grade = Grade.B },
                new Enrollment { EnrollmentID = 4, StudentID = 3, CourseID = 1050, Grade = Grade.B },
                new Enrollment { EnrollmentID = 5, StudentID = 4, CourseID = 2021, Grade = Grade.F }
            };
            context.Enrollments.AddRange(enrollments);

            // Add course assignments
            var courseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { InstructorID = 1, CourseID = 1050 },
                new CourseAssignment { InstructorID = 1, CourseID = 4022 },
                new CourseAssignment { InstructorID = 2, CourseID = 4041 }
            };
            context.CourseAssignments.AddRange(courseAssignments);

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllStudents_WhenNoSearchOrSort()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_WhenSortOrderIsDefault()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending_WhenSortOrderIsNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending_WhenSortOrderIsDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // Earliest enrollment date first
            Assert.Equal(DateTime.Parse("2002-09-01"), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_SortsByDateDescending_WhenSortOrderIsDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(DateTime.Parse("2005-09-01"), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_FiltersStudentsByLastName_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_ResetsPageToOne_WhenNewSearchStringProvided()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            // Default sort => NameSortParm should be "name_desc"
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            // When sorted by name_desc => NameSortParm should be ""
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            // Default sort => DateSortParm should be "Date"
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            // When sorted by Date => DateSortParm should be "date_desc"
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenSearchMatchesNoStudents()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsView_WhenStudentExists()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
            Assert.Equal("Carson", student.FirstMidName);
        }

        [Fact]
        public void Details_IncludesEnrollments_WhenStudentExists()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.NotNull(student.Enrollments);
            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_GET_ReturnsView_WithDefaultEnrollmentDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_AddsStudentToDatabase_WhenModelIsValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            _controller.Create(student);

            Assert.Contains(_context.Students, s => s.LastName == "Student" && s.FirstMidName == "Test");
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_POST_AddsModelError_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            _controller.Create(student);

            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_POST_AddsModelError_WhenEnrollmentDateIsOutOfRange()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            _controller.Create(student);

            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WhenStudentExists()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Edit POST Tests

        [Fact]
        public void Edit_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Updated",
                EnrollmentDate = DateTime.Parse("2005-09-01")
            };

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2005-09-01")
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_AddsModelError_WhenEnrollmentDateIsDefault()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = default
            };

            _controller.Edit(student);

            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Delete GET Tests

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WhenStudentExists()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Delete POST Tests

        [Fact]
        public void DeleteConfirmed_RemovesStudent_AndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Students.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex_WhenExceptionOccurs()
        {
            // ID 999 doesn't exist - will throw
            var result = _controller.DeleteConfirmed(999) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        #endregion
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _testRootPath;

        public CoursesControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _testRootPath = Path.Combine(Path.GetTempPath(), $"CoursesTest_{Guid.NewGuid()}");
            Directory.CreateDirectory(_testRootPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_testRootPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_testRootPath);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_testRootPath))
            {
                try { Directory.Delete(_testRootPath, true); } catch { }
            }
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(4, courses.Count);
        }

        [Fact]
        public void Index_IncludesDepartmentInformation()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.All(courses, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_GET_ReturnsView_WithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_AddsCourseToDatabase_WhenValid()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null!);

            Assert.Contains(_context.Courses, c => c.CourseID == 8888);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_UploadsImage_WhenValidImageProvided()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(6666);
            Assert.NotNull(savedCourse);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_RejectsInvalidFileExtension()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Bad File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_RejectsFileLargerThan5MB()
        {
            var course = new Course
            {
                CourseID = 4444,
                Title = "Large File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

