using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / Student / Instructor Tests

        [Fact]
        public void Person_FullName_ReturnsCombinedName()
        {
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander"
            };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Student_Properties_SetCorrectly()
        {
            var date = DateTime.Parse("2023-01-15");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = date,
                Enrollments = new List<Enrollment>()
            };

            Assert.Equal(1, student.ID);
            Assert.Equal("Test", student.FirstMidName);
            Assert.Equal("Student", student.LastName);
            Assert.Equal(date, student.EnrollmentDate);
            Assert.Empty(student.Enrollments);
        }

        [Fact]
        public void Instructor_Properties_SetCorrectly()
        {
            var date = DateTime.Parse("2020-03-01");
            var instructor = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = date,
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.Equal(1, instructor.ID);
            Assert.Equal("Kim", instructor.FirstMidName);
            Assert.Equal("Abercrombie", instructor.LastName);
            Assert.Equal(date, instructor.HireDate);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Student_LastName_RequiredValidation()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = null!,
                EnrollmentDate = DateTime.Today
            };

            var validationResults = ValidateModel(student);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_RequiredValidation()
        {
            var student = new Student
            {
                FirstMidName = null!,
                LastName = "Test",
                EnrollmentDate = DateTime.Today
            };

            var validationResults = ValidateModel(student);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastName_MaxLengthValidation()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = new string('A', 51),
                EnrollmentDate = DateTime.Today
            };

            var validationResults = ValidateModel(student);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_MaxLengthValidation()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Test",
                EnrollmentDate = DateTime.Today
            };

            var validationResults = ValidateModel(student);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("FirstMidName"));
        }

        #endregion

        #region Course Tests

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_Credits_RangeValidation_TooHigh()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 6,
                DepartmentID = 1
            };

            var validationResults = ValidateModel(course);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_RangeValidation_Negative()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = -1,
                DepartmentID = 1
            };

            var validationResults = ValidateModel(course);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_ValidRange_NoError()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Course",
                Credits = 3,
                DepartmentID = 1
            };

            var validationResults = ValidateModel(course);
            Assert.DoesNotContain(validationResults, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Title_MinLengthValidation()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var validationResults = ValidateModel(course);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Title_MaxLengthValidation()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var validationResults = ValidateModel(course);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Title"));
        }

        #endregion

        #region Department Tests

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("English", dept.Name);
            Assert.Equal(350000, dept.Budget);
            Assert.Equal(1, dept.InstructorID);
        }

        [Fact]
        public void Department_Name_MinLengthValidation()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Today
            };

            var validationResults = ValidateModel(dept);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department
            {
                Name = "Physics",
                Budget = 100000,
                StartDate = DateTime.Today,
                InstructorID = null
            };

            Assert.Null(dept.InstructorID);
        }

        #endregion

        #region Enrollment Tests

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Grade_Enum_HasCorrectValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region Notification Tests

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = DateTime.Now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_Enum_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region CourseAssignment Tests

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal(1050, assignment.CourseID);
        }

        #endregion

        #region OfficeAssignment Tests

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Smith 17", office.Location);
        }

        [Fact]
        public void OfficeAssignment_Location_MaxLengthValidation()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('A', 51)
            };

            var validationResults = ValidateModel(office);
            Assert.Contains(validationResults, v => v.MemberNames.Contains("Location"));
        }

        #endregion

        #region ViewModel Tests

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.Empty(data.Instructors);
            Assert.Empty(data.Courses);
            Assert.Empty(data.Enrollments);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2023-01-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2023-01-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = null,
                StudentCount = 0
            };

            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        #endregion

        #region Helper

        private static List<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }

        #endregion
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelper.CreateSeededContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_CanQueryStudents()
        {
            var students = _context.Students.ToList();

            Assert.Equal(5, students.Count);
        }

        [Fact]
        public void Context_CanQueryInstructors()
        {
            var instructors = _context.Instructors.ToList();

            Assert.Equal(3, instructors.Count);
        }

        [Fact]
        public void Context_CanQueryCourses()
        {
            var courses = _context.Courses.ToList();

            Assert.Equal(4, courses.Count);
        }

        [Fact]
        public void Context_CanQueryDepartments()
        {
            var departments = _context.Departments.ToList();

            Assert.Equal(3, departments.Count);
        }

        [Fact]
        public void Context_CanQueryEnrollments()
        {
            var enrollments = _context.Enrollments.ToList();

            Assert.Equal(5, enrollments.Count);
        }

        [Fact]
        public void Context_CanQueryCourseAssignments()
        {
            var assignments = _context.CourseAssignments.ToList();

            Assert.Equal(3, assignments.Count);
        }

        [Fact]
        public void Context_CourseAssignment_HasCompositeKey()
        {
            var assignment = _context.CourseAssignments
                .FirstOrDefault(ca => ca.CourseID == 1050 && ca.InstructorID == 1);

            Assert.NotNull(assignment);
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01"),
                Enrollments = new System.Collections.Generic.List<Enrollment>()
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.FirstOrDefault(s => s.LastName == "Student");
            Assert.NotNull(retrieved);
            Assert.Equal("New", retrieved.FirstMidName);
        }

        [Fact]
        public void Context_CanUpdateStudent()
        {
            var student = _context.Students.First();
            student.LastName = "UpdatedName";
            _context.SaveChanges();

            var updated = _context.Students.Find(student.ID);
            Assert.NotNull(updated);
            Assert.Equal("UpdatedName", updated.LastName);
        }

        [Fact]
        public void Context_CanDeleteStudent()
        {
            var student = _context.Students.First();
            var id = student.ID;
            _context.Students.Remove(student);
            _context.SaveChanges();

            Assert.Null(_context.Students.Find(id));
        }

        [Fact]
        public void Context_IncludeNavigationProperty_Course_Department()
        {
            var course = _context.Courses.Include(c => c.Department).First();

            Assert.NotNull(course.Department);
        }

        [Fact]
        public void Context_IncludeNavigationProperty_Instructor_OfficeAssignment()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 1);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Context_IncludeNavigationProperty_Instructor_CourseAssignments()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.ID == 1);

            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void Context_Student_Enrollments_Navigation()
        {
            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 1);

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Context_TPH_Inheritance_StudentsAndInstructorsSharePersonTable()
        {
            // Both students and instructors should be accessible through People DbSet
            var people = _context.People.ToList();

            Assert.Equal(8, people.Count); // 5 students + 3 instructors
        }
    }
}

