using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllStudents_WhenNoSearchOrSort()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_WhenSortOrderIsDefault()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending_WhenSortOrderIsNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending_WhenSortOrderIsDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(DateTime.Parse("2002-09-01"), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_SortsByDateDescending_WhenSortOrderIsDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(DateTime.Parse("2005-09-01"), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_FiltersStudentsByLastName_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_ResetsPageToOne_WhenNewSearchStringProvided()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenSearchMatchesNoStudents()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

