using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (shared static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE, "Teacher");
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsCreatedBy()
        {
            _service.SendNotification("Department", "5", "Science", EntityOperation.DELETE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_DefaultsCreatedByToSystem_WhenUserNameIsNull()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Course", "1", "Physics", EntityOperation.CREATE, "User");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_GeneratesCreateMessage_WithDisplayName()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_GeneratesUpdateMessage_WithDisplayName()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Teacher");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Course 'Chemistry'", notification.Message);
            Assert.Contains("has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_GeneratesDeleteMessage_WithDisplayName()
        {
            _service.SendNotification("Department", "5", "Art", EntityOperation.DELETE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Department 'Art'", notification.Message);
            Assert.Contains("has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_GeneratesMessage_WithIdFallback_WhenNoDisplayName()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student (ID: 42)", notification.Message);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "7", EntityOperation.UPDATE, "System");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("7", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNotificationsInFIFOOrder()
        {
            _service.SendNotification("First", "1", "First Item", EntityOperation.CREATE, "User");
            _service.SendNotification("Second", "2", "Second Item", EntityOperation.UPDATE, "User");
            _service.SendNotification("Third", "3", "Third Item", EntityOperation.DELETE, "User");

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.NotNull(third);
            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
            Assert.Equal("Third", third.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_HandlesMultipleNotifications()
        {
            for (int i = 0; i < 10; i++)
            {
                _service.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE, "Admin");
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.Equal(10, count);
        }
    }
}

