using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _testRootPath;

        public CoursesControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _testRootPath = Path.Combine(Path.GetTempPath(), $"CoursesTest_{Guid.NewGuid()}");
            Directory.CreateDirectory(_testRootPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_testRootPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_testRootPath);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_testRootPath))
            {
                try { Directory.Delete(_testRootPath, true); } catch { }
            }
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(4, courses.Count);
        }

        [Fact]
        public void Index_IncludesDepartmentInformation()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.All(courses, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_GET_ReturnsView_WithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_AddsCourseToDatabase_WhenValid()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null!);

            Assert.Contains(_context.Courses, c => c.CourseID == 8888);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_UploadsImage_WhenValidImageProvided()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(6666);
            Assert.NotNull(savedCourse);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_RejectsInvalidFileExtension()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Bad File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_RejectsFileLargerThan5MB()
        {
            var course = new Course
            {
                CourseID = 4444,
                Title = "Large File Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit POST Tests

        [Fact]
        public void Edit_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            // Detach tracked entity
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_POST_UploadsNewImage_WhenValidImageProvided()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            // Detach tracked entity
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFormFile("new_image.png", "image/png", 2048);

            var result = _controller.Edit(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        #endregion

        #region Delete GET Tests

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        #endregion

        #region Delete POST Tests

        [Fact]
        public void DeleteConfirmed_RemovesCourse_AndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var fileMock = new Mock<IFormFile>();
            var content = new byte[Math.Min((int)length, 1024)];
            var ms = new MemoryStream(content);

            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.ContentType).Returns(contentType);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.OpenReadStream()).Returns(ms);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));

            return fileMock;
        }

        #endregion
    }
}

