using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var departments = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(3, departments.Count);
        }

        [Fact]
        public void Index_IncludesAdministratorInfo()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var departments = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.All(departments, d => Assert.NotNull(d.Administrator));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Details_ReturnsView_WhenDepartmentExists()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_GET_ReturnsView_WithInstructorSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 250000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 1
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_AddsDepartmentToDatabase_WhenValid()
        {
            var department = new Department
            {
                Name = "Biology",
                Budget = 150000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 2
            };

            _controller.Create(department);

            Assert.Contains(_context.Departments, d => d.Name == "Biology");
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 100000,
                StartDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WhenDepartmentExists()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit POST Tests

        [Fact]
        public void Edit_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1,
                RowVersion = new byte[] { 0, 0, 0, 1 }
            };

            var tracked = _context.Departments.Find(1);
            _context.Entry(tracked!).State = EntityState.Detached;

