using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_OrdersInstructorsByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
            Assert.Equal("Harui", instructors[2].LastName);
        }

        [Fact]
        public void Index_LoadsCoursesForSelectedInstructor()
        {
            var result = _controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count());
        }

        [Fact]
        public void Index_SetsViewBagInstructorID_WhenInstructorSelected()
        {
            _controller.Index(1, null);

            Assert.Equal(1, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_LoadsEnrollmentsForSelectedCourse()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagCourseID_WhenCourseSelected()
        {
            _controller.Index(1, 1050);

            Assert.Equal(1050, _controller.ViewBag.CourseID);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Details_ReturnsView_WhenInstructorExists()
        {
            var result = _controller.Details(1) as ViewResult;

