            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_AddsInstructorToDatabase_WhenValid()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, null!);

            Assert.Contains(_context.Instructors, i => i.LastName == "Smith");
        }

        [Fact]
        public void Create_POST_AssignsCourses_WhenSelectedCoursesProvided()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var selectedCourses = new[] { "1050", "4022" };

            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "Instructor");
            Assert.NotNull(saved);
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

