using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void About_ReturnsView_WithEnrollmentDateGroups()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.Equal(3, model.Count);
            Assert.Contains(model, g => g.StudentCount == 3);
        }

        [Fact]
        public void Contact_ReturnsView_WithMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            var result = _controller.Error() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Unauthorized_ReturnsView_WithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

